  case ICmpInst::ICMP_SGT: // X > C (signed) --> X > C (unsigned)
    return ICmpInst::ICMP_UGT;
  case ICmpInst::ICMP_SLT: // X < C (signed) --> X < C (unsigned)
    return ICmpInst::ICMP_ULT;
  case ICmpInst::ICMP_SGE: // X >= C (signed) --> X >= C (unsigned)
    return ICmpInst::ICMP_UGE;
  case ICmpInst::ICMP_SLE: // X <= C (signed) --> X <= C (unsigned)
    return ICmpInst::ICMP_ULE;
  default:
    llvm_unreachable("Unknown signed comparison");
  }
}

