  case Instruction::And:
    if (C.isAllOnesValue()) {
      // (X & C) == -1  -> X|~C == -1
      if (Constant *C1 = dyn_cast<Constant>(BOp1)) {
        Constant *NotC1 = ConstantExpr::getNot(C1);
        Value *Or = Builder.CreateOr(BOp0, NotC1);
        return new ICmpInst(Pred, Or, RHS);
      }
    } else if (C.isZero()) {
      // (X & C) != 0 -> X != 0 if C is odd.
      const APInt *C1;
      if (match(BOp1, m_APInt(C1)) && C1->isOdd())
