// The following two functions are helper functions for simplifyICmpInst.
// They are not in an anonymous namespace so that they can be used by
// other InstCombine files.
//
/// Given a signed compare, return the equivalent unsigned compare if possible.
ICmpInst::Predicate llvm::getEquivalentICmpOfSigned(ICmpInst::Predicate Pred,
                                                    const APInt &C,
                                                    bool IsSignBitFree) {
  assert(ICmpInst::isSigned(Pred) && "Predicate must be signed");

  // There is no direct unsigned equivalent for signed comparisons with a
  // negative constant.
  if (C.isNegative())
    return ICmpInst::BAD_ICMP_PREDICATE;

  // If the sign bit of the constant is not set, we can convert to an unsigned
  // comparison.
  switch (Pred) {
  case ICmpInst::ICMP_SGT: // X > C (signed) --> X > C (unsigned)
    return ICmpInst::ICMP_UGT;
  case ICmpInst::ICMP_SLT: // X < C (signed) --> X < C (unsigned)
    return ICmpInst::ICMP_ULT;
  case ICmpInst::ICMP_SGE: // X >= C (signed) --> X >= C (unsigned)
    return ICmpInst::ICMP_UGE;
  case ICmpInst::ICMP_SLE: // X <= C (signed) --> X <= C (unsigned)
    return ICmpInst::ICMP_ULE;
  default:
    llvm_unreachable("Unknown signed comparison");
  }
}

/// Given an unsigned compare, return the equivalent signed compare if possible.
ICmpInst::Predicate llvm::getEquivalentICmpOfUnsigned(ICmpInst::Predicate Pred,
                                                      const APInt &C,
                                                      bool IsSignBitFree) {
  assert(ICmpInst::isUnsigned(Pred) && "Predicate must be unsigned");

  // If the sign bit of the constant is set, we cannot convert to a signed
  // comparison.
  if (C.isNegative())
    return ICmpInst::BAD_ICMP_PREDICATE;

  // If the sign bit of the variable is known to be zero, we can convert to a
  // signed comparison.
  if (IsSignBitFree) {
    switch (Pred) {
    case ICmpInst::ICMP_UGT: // X > C (unsigned) --> X > C (signed)
      return ICmpInst::ICMP_SGT;
    case ICmpInst::ICMP_ULT: // X < C (unsigned) --> X < C (signed)
      return ICmpInst::ICMP_SLT;
    case ICmpInst::ICMP_UGE: // X >= C (unsigned) --> X >= C (signed)
      return ICmpInst::ICMP_SGE;
    case ICmpInst::ICMP_ULE: // X <= C (unsigned) --> X <= C (signed)
      return ICmpInst::ICMP_SLE;
    default:
      llvm_unreachable("Unknown unsigned comparison");
    }
  }

  return ICmpInst::BAD_ICMP_PREDICATE;
}

/// Fold an icmp instruction with a constant operand.
Instruction *InstCombinerImpl::foldICmpInstWithConstant(ICmpInst &Cmp) {
  const APInt *C;
  if (!match(Cmp.getOperand(1), m_APInt(C)))
    return nullptr;
  return foldICmpInstWithConstantAllowPoison(Cmp, *C);
}

/// Fold an icmp instruction with a constant operand.
Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
    ICmpInst &Cmp, BinaryOperator *BO, const APInt &C) {
  // TODO: Some of these folds could work with arbitrary constants, but this
  // function is limited to scalar and vector splat constants.
  if (!Cmp.isEquality())
    return nullptr;

  ICmpInst::Predicate Pred = Cmp.getPredicate();
  bool isICMP_NE = Pred == ICmpInst::ICMP_NE;
  Constant *RHS = cast<Constant>(Cmp.getOperand(1));
  Value *BOp0 = BO->getOperand(0), *BOp1 = BO->getOperand(1);

  switch (BO->getOpcode()) {
  case Instruction::SRem:
    // If we have a signed (X % (2^c)) == 0, turn it into an unsigned one.
    if (C.isZero() && BO->hasOneUse()) {
      const APInt *BOC;
      if (match(BOp1, m_APInt(BOC)) && BOC->sgt(1) && BOC->isPowerOf2()) {
        Value *NewRem = Builder.CreateURem(BOp0, BOp1, BO->getName());
        return new ICmpInst(Pred, NewRem,
                            Constant::getNullValue(BO->getType()));
      }
    }
    break;
  case Instruction::Add: {
    // (A + C2) == C --> A == (C - C2)
    // (A + C2) != C --> A != (C - C2)
    // TODO: Remove the one-use limitation? See discussion in D58633.
    if (Constant *C2 = dyn_cast<Constant>(BOp1)) {
      if (BO->hasOneUse())
        return new ICmpInst(Pred, BOp0, ConstantExpr::getSub(RHS, C2));
    } else if (C.isZero()) {
      // Replace ((add A, B) != 0) with (A != -B) if A or B is
      // efficiently invertible, or if the add has just this one use.
      if (Value *NegVal = dyn_castNegVal(BOp1))
        return new ICmpInst(Pred, BOp0, NegVal);
      if (Value *NegVal = dyn_castNegVal(BOp0))
        return new ICmpInst(Pred, NegVal, BOp1);
      if (BO->hasOneUse()) {
        // (add nuw A, B) != 0 -> (or A, B) != 0
        if (match(BO, m_NUWAdd(m_Value(), m_Value()))) {
          Value *Or = Builder.CreateOr(BOp0, BOp1);
          return new ICmpInst(Pred, Or, Constant::getNullValue(BO->getType()));
        }
        Value *Neg = Builder.CreateNeg(BOp1);
        Neg->takeName(BO);
        return new ICmpInst(Pred, BOp0, Neg);
      }
    }
    break;
  }
  case Instruction::Xor:
    if (Constant *BOC = dyn_cast<Constant>(BOp1)) {
      // For the xor case, we can xor two constants together, eliminating
      // the explicit xor.
      return new ICmpInst(Pred, BOp0, ConstantExpr::getXor(RHS, BOC));
    } else if (C.isZero()) {
      // Replace ((xor A, B) != 0) with (A != B)
      return new ICmpInst(Pred, BOp0, BOp1);
    }
    break;
  case Instruction::Or: {
    if (BO->getType()->isVectorTy()) break;
    const APInt *BOC;
    if (match(BOp1, m_APInt(BOC)) && BO->hasOneUse() && RHS->isAllOnesValue()) {
      // Comparing if all bits outside of a constant mask are set?
      // Replace (X | C) == -1 with (X & ~C) == ~C.
      // This removes the -1 constant.
      Constant *NotBOC = ConstantExpr::getNot(cast<Constant>(BOp1));
      Value *And = Builder.CreateAnd(BOp0, NotBOC);
      return new ICmpInst(Pred, And, NotBOC);
    }
    // (icmp eq (or (select cond, 0, NonZero), Other), 0)
    //  -> (and cond, (icmp eq Other, 0))
    // (icmp ne (or (select cond, NonZero, 0), Other), 0)
    //  -> (or cond, (icmp ne Other, 0))
    Value *Cond, *TV, *FV, *Other, *Sel;
    if (C.isZero() &&
        match(BO,
              m_OneUse(m_c_Or(m_CombineAnd(m_Value(Sel),
                                           m_Select(m_Value(Cond), m_Value(TV),
                                                    m_Value(FV))),
                              m_Value(Other))))) {
      const SimplifyQuery Q = SQ.getWithInstruction(&Cmp);
      // Easy case is if eq/ne matches whether 0 is trueval/falseval.
      if (Pred == ICmpInst::ICMP_EQ
              ? (match(TV, m_Zero()) && isKnownNonZero(FV, Q))
              : (match(FV, m_Zero()) && isKnownNonZero(TV, Q))) {
        Value *Cmp = Builder.CreateICmp(
            Pred, Other, Constant::getNullValue(Other->getType()));
        return BinaryOperator::Create(
            Pred == ICmpInst::ICMP_EQ ? Instruction::And : Instruction::Or, Cmp,
            Cond);
      }
      // Harder case is if eq/ne matches whether 0 is falseval/trueval. In this
      // case we need to invert the select condition so we need to be careful to
      // avoid creating extra instructions.
      // (icmp ne (or (select cond, 0, NonZero), Other), 0)
      //  -> (or (not cond), (icmp ne Other, 0))
      // (icmp eq (or (select cond, NonZero, 0), Other), 0)
      //  -> (and (not cond), (icmp eq Other, 0))
      //
      // Only do this if the inner select has one use, in which case we are
      // replacing `select` with `(not cond)`. Otherwise, we will create more
      // uses. NB: Trying to freely invert cond doesn't make sense here, as if
      // cond was freely invertable, the select arms would have been inverted.
      if (Sel->hasOneUse() &&
          (Pred == ICmpInst::ICMP_EQ
               ? (match(FV, m_Zero()) && isKnownNonZero(TV, Q))
               : (match(TV, m_Zero()) && isKnownNonZero(FV, Q)))) {
        Value *NotCond = Builder.CreateNot(Cond);
        Value *Cmp = Builder.CreateICmp(
            Pred, Other, Constant::getNullValue(Other->getType()));
        return BinaryOperator::Create(
            Pred == ICmpInst::ICMP_EQ ? Instruction::And : Instruction::Or, Cmp,
            NotCond);
      }
    }

    // (X|C) == 0 is equivalent to (X&~C) == 0.
    // (X|C) != 0 is equivalent to (X&~C) != 0.
    // This is not a good transform if C has many bits set.
    if (C.isZero() && BO->hasOneUse()) {
      if (Constant *C1 = dyn_cast<Constant>(BOp1)) {
        if (isa<Constant>(BOp0))
          break;
        // If C1 is a large constant, this is not a good transform.
        if (C1->getType()->isIntegerTy() &&
            C1->getType()->getIntegerBitWidth() > 2) {
          const APInt *Val = getIntVal(C1);
          if (Val && Val->countPopulation() > Val->getBitWidth() / 2)
            break;
        }

        Constant *NotC1 = ConstantExpr::getNot(C1);
        Value *And = Builder.CreateAnd(BOp0, NotC1);
        return new ICmpInst(Pred, And, Constant::getNullValue(BO->getType()));
      }
    }
    break;
  }
  case Instruction::And:
    if (C.isAllOnesValue()) {
      // (X & C) == -1  -> X|~C == -1
      if (Constant *C1 = dyn_cast<Constant>(BOp1)) {
        Constant *NotC1 = ConstantExpr::getNot(C1);
        Value *Or = Builder.CreateOr(BOp0, NotC1);
        return new ICmpInst(Pred, Or, RHS);
      }
    } else if (C.isZero()) {
      // (X & C) != 0 -> X != 0 if C is odd.
      const APInt *C1;
      if (match(BOp1, m_APInt(C1)) && C1->isOdd())
        return new ICmpInst(Pred, BOp0, Constant::getNullValue(BOp0->getType()));
    }
    break;
  }

  // We can't handle this here, but we can handle it with other routines.
  if (auto *II = dyn_cast<IntrinsicInst>(BO))
    return foldICmpIntrinsicEqualityWithConstant(Cmp, II, C);

  return nullptr;
}

/// Handle icmp with constant (but not simple integer constant) RHS.
Instruction *InstCombinerImpl::foldICmpInstWithConstantNotInt(ICmpInst &I) {
  Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
  Constant *RHSC = dyn_cast<Constant>(Op1);
  Instruction *LHSI = dyn_cast<Instruction>(Op0);
